// Prometheus'tan gelen toplu veri paketini servis bazında ayrıştır
const results = $input.first().json.data.result;
const services = {};

for (const r of results) {
  const metricName = r.metric.__name__;
  const instance = r.metric.instance;
  const servisAdi = instance.split(':')[0];

  if (!services[servisAdi]) {
    services[servisAdi] = { servis: servisAdi, instance };
  }

  if (metricName === 'process_resident_memory_bytes') {
    const bytes = parseFloat(r.value[1]);
    services[servisAdi].ram_bytes = bytes;
    services[servisAdi].ram_mb = parseFloat((bytes / 1048576).toFixed(2));
  } else if (metricName === 'up') {
    services[servisAdi].up = r.value[1] === '0' ? 0 : 1;
  }
}

const beklenenServisler = ['servis_a', 'servis_b', 'servis_c'];
for (const s of beklenenServisler) {
  if (!services[s]) services[s] = { servis: s, instance: s + ':5000', ram_mb: 0, ram_bytes: 0, up: 0 };
  if (services[s].up === undefined) services[s].up = 1;
  if (services[s].ram_mb === undefined) services[s].ram_mb = 0;
}

// Predictive maintenance: RAM 150MB ustu ise risk olarak isaretle.
const izlenecekServisler = Object.values(services)
  .filter((s) => s.ram_mb > 150 || s.up === 0)
  .map((s) => ({
    ...s,
    predictive_risk: s.up === 0 ? 'CRITICAL' : (s.ram_mb > 200 ? 'HIGH' : 'EARLY_WARNING')
  }));

// Risk yoksa sonraki nodelara item gitmesin.
return [{ json: { servisler: izlenecekServisler } }];

// Ağ metrik adından Docker konteyner adını dinamik olarak türet
// Raporda belirtilen: JavaScript'in split() ve replace() fonksiyonlarıyla
// ağ verileri Docker'ın anlayabileceği konteyner isimlerine dönüştürülür

const instance = $json.instance || ($json.servis + ':5000');

// 'servis_a:5000' → 'servis_a' (split ile port kısmını ayır)
const servisAdi = instance.split(':')[0];

// 'servis_a' → 'tasarim_proje-servis_a-1' (Docker compose naming convention)
// Olası tire/boşluk hatalarını önlemek için replace ile normalize et
const containerName = 'tasarim_proje-' + servisAdi.replace(/ /g, '_') + '-1';

return [{
  json: {
    ...$json,
    containerName
  }
}];

